const { Pool } = require('pg');

/**
 * Updates a user's profile in the PostgreSQL database.
 * @param {Pool} pool - The PostgreSQL connection pool.
 * @param {string} userId - The ID of the user to update.
 * @param {object} profileData - An object containing the profile data to update.
 *                               Keys should be column names and values the new data.
 * @returns {Promise<object | null>} The updated user profile or null if not found.
 */
async function updateUserProfile(pool, userId, profileData) {
  if (!pool || !userId || !profileData || Object.keys(profileData).length === 0) {
    throw new Error('Invalid input: pool, userId, and profileData (non-empty) are required.');
  }

  const updates = [];
  const values = [];
  let paramIndex = 1;

  for (const key in profileData) {
    if (Object.prototype.hasOwnProperty.call(profileData, key)) {
      updates.push(`${key} = $${paramIndex}`);
      values.push(profileData[key]);
      paramIndex++;
    }
  }

  values.push(userId); // Add userId as the last parameter

  const query = `
    UPDATE users
    SET ${updates.join(', ')}
    WHERE id = $${paramIndex}
    RETURNING *;
  `;

  try {
    const res = await pool.query(query, values);
    return res.rows[0] || null;
  } catch (error) {
    console.error('Error updating user profile:', error);
    throw error;
  }
}

