/**
 * Makes an authenticated request to a third-party API.
 * @param {string} url The URL of the API endpoint.
 * @param {string} method The HTTP method (e.g., 'GET', 'POST').
 * @param {object} [data] The data payload for POST/PUT requests.
 * @param {string} authToken The authentication token (e.g., Bearer token, API key).
 * @param {object} [headers] Additional headers to include in the request.
 * @returns {Promise<object>} The API response data.
 * @throws {Error} If the API request fails.
 */
async function callExternalApi(url, method, data = {}, authToken, headers = {}) {
  try {
    const config = {
      method: method.toLowerCase(),
      url: url,
      headers: {
        'Authorization': `Bearer ${authToken}`, // Or 'x-api-key': authToken for API key authentication
        'Content-Type': 'application/json',
        ...headers,
      },
      data: data,
    };

    // If it's a GET or HEAD request, data should be in params
    if (method.toLowerCase() === 'get' || method.toLowerCase() === 'head') {
      config.params = data;
      delete config.data; // Remove data from body for GET/HEAD
    }

    const response = await axios(config);
    return response.data;
  } catch (error) {
    if (error.response) {
      // The request was made and the server responded with a status code
      // that falls out of the range of 2xx
      throw new Error(`API Error: ${error.response.status} - ${JSON.stringify(error.response.data)}`);
    } else if (error.request) {
      // The request was made but no response was received
      throw new Error(`API Error: No response received from ${url}`);
    } else {
      // Something happened in setting up the request that triggered an Error
      throw new Error(`API Error: ${error.message}`);
    }
  }
}

