const axios = require('axios');

/**
 * Makes an authenticated request to a third-party API.
 * @param {string} url - The URL of the API endpoint.
 * @param {string} [method='GET'] - The HTTP method (e.g., 'GET', 'POST', 'PUT', 'DELETE').
 * @param {object} [data=null] - The request body data (for 'POST', 'PUT', 'PATCH' methods).
 * @param {string} [token=null] - The authentication token (e.g., a Bearer token).
 * @returns {Promise<object>} The response data from the API.
 * @throws {Error} If the API request fails.
 */
async function callExternalApi(url, method = 'GET', data = null, token = null) {
  try {
    const headers = {
      'Content-Type': 'application/json',
    };

    if (token) {
      headers['Authorization'] = `Bearer ${token}`;
    }

    const config = {
      method: method.toLowerCase(),
      url,
      headers,
      data, // Axios automatically handles data for POST/PUT/PATCH
    };

    const response = await axios(config);
    return response.data;
  } catch (error) {
    console.error('Error calling external API:', error.message);
    if (error.response) {
      // The request was made and the server responded with a status code
      // that falls out of the range of 2xx
      console.error('Response data:', error.response.data);
      console.error('Response status:', error.response.status);
      console.error('Response headers:', error.response.headers);
    } else if (error.request) {
      // The request was made but no response was received
      // `error.request` is an instance of XMLHttpRequest in the browser and an instance of
      // http.ClientRequest in node.js
      console.error('No response received:', error.request);
    } else {
      // Something happened in setting up the request that triggered an Error
      console.error('Error setting up request:', error.message);
    }
    throw error; // Re-throw the error for the caller to handle
  }
}

